import React from 'react';

//import logo from './logo.svg';
import './App.css';
import Header from './components/header/Header';
import Main from './components/main/Main';
import { BrowserRouter, Routes} from 'react-router-dom';

function App() {
  return (
    <BrowserRouter>
    <Routes>
    <div className='App'>
      <Header />
        <div className='main'>
          <Route component={Main}/>
          <Route component={Main}/>

        </div>

    </div>
    </Routes>
    </BrowserRouter>
  );
}

export default App;
